mapper.select:
SELECT
    (SELECT IFNULL(SUM(pay_total_amt), 0) FROM tb_order 
     WHERE DATE(order_dt) = CURDATE()

         AND op_type = #{opType}

    ) AS todaySales,

    (SELECT COUNT(*) FROM tb_order 
     WHERE DATE(order_dt) = CURDATE()

         AND op_type = #{opType}

    ) AS todayOrderCount,

    (SELECT COUNT(*) FROM tb_order 
     WHERE order_status_cd = 'PAY_COMP'

         AND op_type = #{opType}

    ) AS readyShippingCount,

    (SELECT COUNT(*) FROM tb_user 
     WHERE DATE(created_at) = CURDATE()

         AND channel_id = #{opType}

    ) AS todayNewMemberCount

SELECT DATE_FORMAT(order_dt, '%m-%d') AS saleDate, IFNULL(SUM(pay_total_amt), 0) AS dailySales FROM tb_order WHERE order_dt >= CURDATE() - INTERVAL 6 DAY
AND op_type = #{opType}
GROUP BY DATE_FORMAT(order_dt, '%m-%d') ORDER BY saleDate ASC

SELECT order_id AS orderId, order_no AS orderTitle, goods_total_amt AS totalAmt, pay_total_amt AS payAmt, order_status_cd AS orderStatus, DATE_FORMAT(order_dt, '%Y-%m-%d %H:%i') AS regDt, buyer_member_id AS memberId, receiver_name AS ordererName FROM tb_order WHERE del_yn = 'N'
AND op_type = #{opType}
ORDER BY order_dt DESC LIMIT 5
